infinite;\n}\n\n\n\n.chat-body[_ngcontent-%COMP%] {\n  padding: 16px;\n  min-height: 340px;\n  max-height: 400px;\n  overflow-y: auto;\n  display: flex;\n  flex-direction: column;\n  gap: 10px;\n  background:\n    radial-gradient(circle at 20% 80%, rgba(45,106,79,0.08), transparent 50%),\n    radial-gradient(circle at 80% 20%, rgba(212,160,23,0.05), transparent 50%),\n    #0D2818;\n  scrollbar-width: thin;\n  scrollbar-color: rgba(255,255,255,0.1) transparent;\n}\n\n\n\n.chat-date[_ngcontent-%COMP%] {\n  text-align: center;\n  padding: 6px 0;\n}\n.chat-date[_ngcontent-%COMP%]   span[_ngcontent-%COMP%] {\n  background: rgba(255,255,255,0.08);\n  color: rgba(255,255,255,0.5);\n  font-size: 0.7rem;\n  font-weight: 500;\n  padding: 3px 12px;\n  border-radius: var(--radius-full);\n}\n\n\n\n.chat-row[_ngcontent-%COMP%] {\n  display: flex;\n  align-items: flex-end;\n  gap: 8px;\n  animation: fadeInUp 0.35s var(--ease-out-expo) both;\n}\n.chat-row-left[_ngcontent-%COMP%] { justify-content: flex-start; }\n.chat-row-right[_ngcontent-%COMP%] { flex-direction: row-reverse; }\n\n.chat-avatar[_ngcontent-%COMP%] {\n  width: 30px;\n  height: 30px;\n  border-radius: 50%;\n  object-fit: cover;\n  flex-shrink: 0;\n  border: 1.5px solid rgba(255,255,255,0.15);\n}\n\n\n\n.chat-bubble[_ngcontent-%COMP%] {\n  max-width: 75%;\n  padding: 10px 14px;\n  border-radius: 16px;\n  position: relative;\n}\n.bubble-jp[_ngcontent-%COMP%] {\n  background: rgba(255,255,255,0.1);\n  border-bottom-left-radius: 4px;\n  color: rgba(255,255,255,0.92);\n}\n.bubble-carine[_ngcontent-%COMP%] {\n  background: linear-gradient(135deg, var(--mt-emerald), #1B6B40);\n  border-bottom-right-radius: 4px;\n  color: white;\n}\n.bubble-text[_ngcontent-%COMP%] {\n  font-size: 0.85rem;\n  line-height: 1.5;\n  margin: 0;\n}\n.bubble-time[_ngcontent-%COMP%] {\n  display: block;\n  text-align: right;\n  font-size: 0.6rem;\n  opacity: 0.5;\n  margin-top: 4px;\n}\n\n\n\n.typing-indicator[_ngcontent-%COMP%] {\n  display: flex;\n  align-items: center;\n  gap: 4px;\n  padding: 12px 18px;\n  border-radius: 16px;\n  border-bottom-left-radius: 4px;\n}\n.typing-indicator.bubble-jp[_ngcontent-%COMP%] { background: rgba(255,255,255,0.1); }\n.typing-indicator.bubble-carine[_ngcontent-%COMP%] { background: linear-gradient(135deg, var(--mt-emerald), #1B6B40); }\n.typing-indicator[_ngcontent-%COMP%]   .dot[_ngcontent-%COMP%] {\n  width: 7px;\n  height: 7px;\n  border-radius: 50%;\n  background: rgba(255,255,255,0.5);\n  animation: _ngcontent-%COMP%_typingBounce 1.2s ease-in-out infinite;\n}\n.typing-indicator[_ngcontent-%COMP%]   .dot[_ngcontent-%COMP%]:nth-child(2) { animation-delay: 0.15s; }\n.typing-indicator[_ngcontent-%COMP%]   .dot[_ngcontent-%COMP%]:nth-child(3) { animation-delay: 0.3s; }\n\n@keyframes _ngcontent-%COMP%_typingBounce {\n  0%, 60%, 100% { transform: translateY(0); opacity: 0.4; }\n  30% { transform: translateY(-5px); opacity: 1; }\n}\n\n@media (max-width: 768px) {\n  .chat-section[_ngcontent-%COMP%] { padding: 2rem 1rem; }\n}\n\n\n\n.result-card[_ngcontent-%COMP%] {\n  position: relative;\n  z-index: 1;\n  max-width: 1360px;\n  margin: -2rem auto 3rem;\n  padding: 2rem 2.5rem;\n  display: flex;\n  align-items: center;\n  gap: 1.5rem;\n  background: white;\n  border-radius: var(--radius-xl);\n  box-shadow: var(--shadow-lg);\n  border-left: 6px solid var(--mt-grey-warm);\n}\n.result-card.verdict-green[_ngcontent-%COMP%] { border-left-color: var(--mt-emerald); }\n.result-card.verdict-red[_ngcontent-%COMP%] { border-left-color: var(--mt-red); }\n.result-card.verdict-yellow[_ngcontent-%COMP%] { border-left-color: var(--mt-gold); }\n.result-card.verdict-pending[_ngcontent-%COMP%] { border-left-color: var(--mt-grey-warm); }\n.result-icon[_ngcontent-%COMP%] { font-size: 2.5rem; flex-shrink: 0; }\n.result-body[_ngcontent-%COMP%] { flex: 1; }\n.result-body[_ngcontent-%COMP%]   h3[_ngcontent-%COMP%] {\n  font-family: var(--font-display);\n  font-size: 1.1rem;\n  margin-bottom: 4px;\n}\n.result-title-num[_ngcontent-%COMP%] { font-weight: 600; font-size: 0.9rem; }\n.result-message[_ngcontent-%COMP%] { color: var(--mt-grey-warm); font-size: 0.9rem; margin: 4px 0; }\n.result-date[_ngcontent-%COMP%] { font-size: 0.75rem; color: var(--mt-grey-warm); }\n\n\n\n.pillars-section[_ngcontent-%COMP%] {\n  position: relative;\n  z-index: 1;\n  max-width: 1360px;\n  margin: 0 auto;\n  padding: 2rem 2rem 5rem;\n}\n.section-title-center[_ngcontent-%COMP%] {\n  text-align: center;\n  font-size: clamp(1.5rem, 3vw, 2rem);\n  color: var(--mt-forest);\n  margin-bottom: 2.5rem;\n}\n.pillars-grid[_ngcontent-%COMP%] {\n  display: grid;\n  grid-template-columns: repeat(4, 1fr);\n  gap: 1.25rem;\n}\n.pillar-card[_ngcontent-%COMP%] {\n  background: rgba(255, 255, 255, 0.65);\n  backdrop-filter: blur(16px);\n  border: 1px solid rgba(255, 255, 255, 0.5);\n  border-radius: var(--radius-lg);\n  padding: 2rem 1.5rem;\n  cursor: pointer;\n  transition: all 0.4s cubic-bezier(0.16, 1, 0.3, 1);\n  position: relative;\n  overflow: hidden;\n}\n.pillar-card[_ngcontent-%COMP%]::after {\n  content: '';\n  position: absolute;\n  inset: 0;\n  background: linear-gradient(135deg, rgba(45, 106, 79, 0.03), rgba(212, 160, 23, 0.03));\n  opacity: 0;\n  transition: opacity 0.4s;\n}\n.pillar-card[_ngcontent-%COMP%]:hover {\n  transform: translateY(-6px);\n  box-shadow: var(--shadow-lg);\n  border-color: rgba(45, 106, 79, 0.15);\n}\n.pillar-card[_ngcontent-%COMP%]:hover::after { opacity: 1; }\n.pillar-icon[_ngcontent-%COMP%] {\n  font-size: 2rem;\n  margin-bottom: 1rem;\n}\n.pillar-card[_ngcontent-%COMP%]   h3[_ngcontent-%COMP%] {\n  font-family: var(--font-display);\n  font-size: 1.15rem;\n  color: var(--mt-forest);\n  margin-bottom: 0.5rem;\n}\n.pillar-card[_ngcontent-%COMP%]   p[_ngcontent-%COMP%] {\n  font-size: 0.85rem;\n  color: var(--mt-grey-warm);\n  line-height: 1.5;\n}\n.pillar-arrow[_ngcontent-%COMP%] {\n  position: absolute;\n  bottom: 1.5rem;\n  right: 1.5rem;\n  font-size: 1.2rem;\n  color: var(--mt-emerald);\n  opacity: 0;\n  transform: translateX(-8px);\n  transition: all 0.3s cubic-bezier(0.16, 1, 0.3, 1);\n}\n.pillar-card[_ngcontent-%COMP%]:hover   .pillar-arrow[_ngcontent-%COMP%] {\n  opacity: 1;\n  transform: translateX(0);\n}\n\n\n\n.footer[_ngcontent-%COMP%] {\n  background: var(--mt-forest-deep);\n  color: rgba(255, 255, 255, 0.6);\n  padding: 3rem 2rem 2rem;\n  margin-top: auto;\n}\n.footer-inner[_ngcontent-%COMP%] {\n  max-width: 1360px;\n  margin: 0 auto;\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  gap: 1.5rem;\n}\n.footer-logo[_ngcontent-%COMP%] {\n  width: 80px;\n  height: 80px;\n  object-fit: contain;\n  filter: brightness(1.3);\n}\n.footer-tagline[_ngcontent-%COMP%] {\n  font-family: var(--font-display);\n  font-weight: 600;\n  color: var(--mt-gold);\n  font-size: 0.9rem;\n  margin-top: 6px;\n}\n.footer-brand[_ngcontent-%COMP%] {\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n}\n.footer-links[_ngcontent-%COMP%] {\n  display: flex;\n  gap: 2rem;\n}\n.footer-links[_ngcontent-%COMP%]   a[_ngcontent-%COMP%] {\n  color: rgba(255, 255, 255, 0.5);\n  font-size: 0.85rem;\n  font-weight: 500;\n  cursor: pointer;\n  transition: color 0.3s;\n}\n.footer-links[_ngcontent-%COMP%]   a[_ngcontent-%COMP%]:hover { color: var(--mt-gold); }\n.footer-copy[_ngcontent-%COMP%] {\n  font-size: 0.75rem;\n  padding-top: 1.5rem;\n  border-top: 1px solid rgba(255, 255, 255, 0.06);\n  width: 100%;\n  text-align: center;\n}\n\n\n\n@media (max-width: 1024px) {\n  .pillars-grid[_ngcontent-%COMP%] { grid-template-columns: repeat(2, 1fr); }\n  .hero-content[_ngcontent-%COMP%] { grid-template-columns: 1fr; gap: 2rem; }\n  .hero-right[_ngcontent-%COMP%] { display: none; }\n  .hero-content[_ngcontent-%COMP%] { min-height: auto; padding: 3rem 2rem; }\n}\n\n@media (max-width: 768px) {\n  .header[_ngcontent-%COMP%] { padding: 0 1rem; }\n  .nav-desktop[_ngcontent-%COMP%] { display: none; }\n  .hamburger[_ngcontent-%COMP%] { display: flex; }\n  .mobile-menu[_ngcontent-%COMP%] { display: block; }\n  .pillars-grid[_ngcontent-%COMP%] { grid-template-columns: 1fr; }\n  .search-box[_ngcontent-%COMP%] { flex-direction: column; }\n  .search-btn[_ngcontent-%COMP%] { width: 100%; }\n  .result-card[_ngcontent-%COMP%] {\n    flex-direction: column;\n    text-align: center;\n    margin: 0 1rem 2rem;\n    padding: 1.5rem;\n  }\n  .view-section[_ngcontent-%COMP%] { padding: 1.5rem 1rem 3rem; }\n  .hero-title[_ngcontent-%COMP%] { font-size: 2rem; }\n}\n\n/*# sourceMappingURL=data:application/json;charset=utf-8;base64, */"]
