                fill="rgba(45, 106, 79, 0.06)"
                stroke="var(--mt-emerald)"
                stroke-width="1.5"
                stroke-opacity="0.3"/>

              <!-- Network lines (notary connections) -->
              <g class="network-lines">
                <path *ngFor="let line of networkLines; let i = index"
                      [attr.d]="getCityLine(line)"
                      stroke="var(--mt-sage)"
                      stroke-width="1"
                      stroke-dasharray="4,4"
                      fill="none"
                      [attr.opacity]="cities[line[0]].checked && cities[line[1]].checked ? 0.6 : 0.15"
                      style="transition: opacity 0.8s ease;"/>
              </g>

              <!-- City nodes -->
              <g *ngFor="let city of cities; let i = index"
                 class="city-node"
                 (mouseenter)="hoveredCity = city"
                 (mouseleave)="hoveredCity = null">

                <!-- Scan pulse ring -->
                <circle *ngIf="city.scanning"
                        [attr.cx]="city.x" [attr.cy]="city.y" r="30"
                        fill="url(#scanPulse)"
                        class="scan-pulse"/>

                <!-- City dot -->
                <circle [attr.cx]="city.x" [attr.cy]="city.y"
                        [attr.r]="city.scanning ? 9 : city.checked ? 8 : 5"
                        [class.dot-unchecked]="!city.checked && !city.scanning"
                        [class.dot-scanning]="city.scanning"
                        [class.dot-green]="city.checked && city.status === 'GREEN'"
                        [class.dot-red]="city.checked && city.status === 'RED'"
                        [class.dot-yellow]="city.checked && city.status === 'YELLOW'"
                        class="city-dot"
                        filter="url(#glow)"/>

                <!-- Status icon -->
                <text *ngIf="city.checked && !city.scanning"
                      [attr.x]="city.x" [attr.y]="city.y + 4"
                      text-anchor="middle" fill="white" font-size="9" font-weight="bold"
                      class="status-check">
                  {{ city.status === 'GREEN' ? '✓' : city.status === 'RED' ? '✗' : '!' }}
                </text>

                <!-- Scanning icon -->
                <text *ngIf="city.scanning"
                      [attr.x]="city.x" [attr.y]="city.y + 4"
                      text-anchor="middle" fill="white" font-size="10"
                      class="scanning-icon">
                  🔍
                </text>

                <!-- City label -->
                <text [attr.x]="city.x" [attr.y]="city.y + 22"
                      text-anchor="middle"
                      class="city-label"
                      [class.label-active]="city.checked || city.scanning">
                  {{ city.name }}
                </text>

                <!-- Notary indicator -->
                <text *ngIf="city.checked"
                      [attr.x]="city.x" [attr.y]="city.y + 34"
                      text-anchor="middle" class="notary-label">
                  {{ city.notary }}
                </text>
              </g>

              <!-- Magnifying glass on scanning city -->
              <g *ngIf="scanningCity" class="magnifier-overlay"
                 [attr.transform]="'translate(' + scanningCity.x + ',' + scanningCity.y + ')'">
                <circle r="28" fill="none" stroke="#D4A017" stroke-width="2.5" opacity="0.6" class="magnifier-ring"/>
                <circle r="22" fill="rgba(212, 160, 23, 0.05)" stroke="none"/>
                <line x1="19" y1="19" x2="32" y2="32" stroke="#D4A017" stroke-width="3" stroke-linecap="round" opacity="0.6"/>
              </g>
            </svg>

            <!-- Tooltip au survol -->
            <div *ngIf="hoveredCity" class="city-tooltip"
                 [style.left.px]="hoveredCity.x + 20"
                 [style.top.px]="hoveredCity.y - 20">
              <div class="tooltip-header">
                <span class="tooltip-city">{{ hoveredCity.name }}</span>
                <span class="tooltip-badge"
                      [class.badge-green]="hoveredCity.checked && hoveredCity.status === 'GREEN'"
                      [class.badge-red]="hoveredCity.checked && hoveredCity.status === 'RED'"
                      [class.badge-yellow]="hoveredCity.checked && hoveredCity.status === 'YELLOW'"
                      *ngIf="hoveredCity.checked">
                  {{ hoveredCity.status === 'GREEN' ? 'Sûr' : hoveredCity.status === 'RED' ? 'Litige' : 'Prudence' }}
                </span>
              </div>
              <div class="tooltip-row">{{ hoveredCity.title }} · {{ hoveredCity.surface }} m²</div>
              <div class="tooltip-notary">⚖️ {{ hoveredCity.notary }}</div>
              <div *ngIf="!hoveredCity.checked" class="tooltip-pending">En attente d'arbitrage...</div>
            </div>

            <!-- Stats bar -->
            <div class="map-stats">
              <div class="stat-chip stat-green">
                <span class="stat-dot" style="background: var(--mt-emerald);"></span>
                <span class="stat-num">{{ getCheckedCount('GREEN') }}</span> validés
              </div>
              <div class="stat-chip stat-red">
                <span class="stat-dot" style="background: var(--mt-red);"></span>
                <span class="stat-num">{{ getCheckedCount('RED') }}</span> litiges
              </div>
              <div class="stat-chip stat-pending">
                <span class="stat-dot" style="background: var(--mt-gold);"></span>
                <span class="stat-num">{{ getCheckedCount('PENDING') }}</span> en cours
              </div>
            </div>
          </div>
        </div>
      </div>

      <!-- Result -->
      <div *ngIf="verificationResult" class="result-card animate-in" [ngClass]="getStatusClass(verificationResult.status)">
        <div class="result-icon">
          {{ verificationResult.status === 'GREEN' ? '✅' : verificationResult.status === 'RED' ? '🚫' : verificationResult.status === 'YELLOW' ? '⚠️' : '⏳' }}
        </div>
        <div class="result-body">
          <h3>Résultat de l'Arbitrage</h3>
          <p class="result-title-num">Titre : {{ verificationResult.title }}</p>
          <p class="result-message">{{ verificationResult.message }}</p>
          <p class="result-date">Vérifié le {{ verificationResult.date }}</p>
        </div>
        <button *ngIf="verificationResult.status !== 'PENDING'" (click)="downloadPdf()" class="btn btn-gold btn-sm">
          📄 Rapport PDF
        </button>
      </div>

      <!-- Interactive Chat -->
      <div class="chat-section animate-in">
        <h2 class="section-title-center">Ils ont sécurisé leur foncier</h2>
        <div class="chat-window">
          <div class="chat-header-bar">
            <div class="chat-header-avatars">
              <img src="https://randomuser.me/api/portraits/men/32.jpg" alt="Jean-Pierre" class="chat-header-pic"/>
              <img src="https://randomuser.me/api/portraits/women/44.jpg" alt="Carine" class="chat-header-pic"/>
            </div>
            <div class="chat-header-info">
              <span class="chat-header-names">Jean-Pierre & Carine</span>
              <span class="chat-header-status">
                <span class="online-dot"></span> En ligne
              </span>
            </div>
          </div>

          <div class="chat-body">
            <ng-container *ngFor="let msg of visibleMessages; let i = index">
              <!-- Date separator -->
              <div *ngIf="msg.type === 'date'" class="chat-date">
                <span>{{ msg.text }}</span>
              </div>

              <!-- Message bubble -->
              <div *ngIf="msg.type === 'msg'" class="chat-row"
                   [class.chat-row-right]="msg.sender === 'carine'"
                   [class.chat-row-left]="msg.sender === 'jp'">
                <img [src]="msg.sender === 'jp' ? 'https://randomuser.me/api/portraits/men/32.jpg' : 'https://randomuser.me/api/portraits/women/44.jpg'"
                     [alt]="msg.sender === 'jp' ? 'Jean-Pierre' : 'Carine'"
                     class="chat-avatar"/>
                <div class="chat-bubble"
                     [class.bubble-jp]="msg.sender === 'jp'"
                     [class.bubble-carine]="msg.sender === 'carine'">
                  <p class="bubble-text">{{ msg.text }}</p>
                  <span class="bubble-time">{{ msg.time }}</span>
                </div>
              </div>
            </ng-container>

            <!-- Typing indicator -->
            <div *ngIf="isTyping" class="chat-row"
                 [class.chat-row-right]="typingSender === 'carine'"
                 [class.chat-row-left]="typingSender === 'jp'">
              <img [src]="typingSender === 'jp' ? 'https://randomuser.me/api/portraits/men/32.jpg' : 'https://randomuser.me/api/portraits/women/44.jpg'"
                   alt="" class="chat-avatar"/>
              <div class="typing-indicator"
                   [class.bubble-jp]="typingSender === 'jp'"
                   [class.bubble-carine]="typingSender === 'carine'">
                <span class="dot"></span><span class="dot"></span><span class="dot"></span>
              </div>
            </div>
          </div>
        </div>
      </div>

      <!-- Pillars -->
      <div class="pillars-section">
        <h2 class="section-title-center">Les 4 Piliers de Confiance</h2>
        <div class="pillars-grid stagger">
          <div class="pillar-card" (click)="navigate('CATALOGUE')">
            <div class="pillar-icon">🏠</div>
            <h3>Acheter</h3>
            <p>Catalogue de terrains certifiés. Filtre « zéro risque » activé.</p>
            <span class="pillar-arrow">→</span>
          </div>
          <div class="pillar-card" (click)="navigate('VERIFY')">
            <div class="pillar-icon">🔍</div>
            <h3>Vérifier</h3>
            <p>Arbitrage notarial express. Rapport en 48 heures.</p>
            <span class="pillar-arrow">→</span>
          </div>
          <div class="pillar-card" (click)="navigate('TITRE')">
            <div class="pillar-icon">📋</div>
            <h3>Titrer</h3>
            <p>Accélérateur administratif MINDCAF. Suivi en temps réel.</p>
            <span class="pillar-arrow">→</span>
          </div>
          <div class="pillar-card" (click)="navigate('PREINVEST')">
            <div class="pillar-icon">💡</div>
            <h3>Pré-Investir</h3>
            <p>maTerre finance le titrage. Vous récoltez la plus-value.</p>
            <span class="pillar-arrow">→</span>
          </div>
        </div>
      </div>
    </section>

    <!-- ─── Sub-views ─── -->
    <section *ngIf="currentView === 'CATALOGUE'" class="view-section animate-in"><app-catalogue></app-catalogue></section>
    <section *ngIf="currentView === 'NOTARY'" class="view-section animate-in"><app-notary-dashboard></app-notary-dashboard></section>
    <section *ngIf="currentView === 'TITRE'" class="view-section animate-in"><app-titling-tracker></app-titling-tracker></section>
    <section *ngIf="currentView === 'PREINVEST'" class="view-section animate-in"><app-pre-invest-dashboard></app-pre-invest-dashboard></section>
    <section *ngIf="currentView === 'COINVEST'" class="view-section animate-in"><app-investment-marketplace></app-investment-marketplace></section>
    <section *ngIf="currentView === 'CLUB'" class="view-section animate-in"><app-subscription></app-subscription></section>
    <section *ngIf="currentView === 'PORTFOLIO'" class="view-section animate-in"><app-investor-dashboard></app-investor-dashboard></section>
    <section *ngIf="currentView === 'ADMIN'" class="view-section animate-in"><app-admin-dashboard></app-admin-dashboard></section>
  </main>

  <!-- ═══ FOOTER ═══ -->
  <footer class="footer">
    <div class="footer-inner">
      <div class="footer-brand">
        <img src="assets/icons/logo.png" alt="maTerre" class="footer-logo">
        <p class="footer-tagline">La Clé d'un Foncier Sûr.</p>
      </div>
      <div class="footer-links">
        <a (click)="navigate('VERIFY')">Vérifier</a>
        <a (click)="navigate('CATALOGUE')">Catalogue</a>
        <a (click)="navigate('TITRE')">Titrer</a>
        <a (click)="navigate('CLUB')">Club Elite</a>
      </div>
      <div class="footer-copy">
        &copy; 2024 maTerre — L'Arbitre du Foncier au Cameroun
      </div>
    </div>
  </footer>

  <!-- ═══ LOGIN MODAL ═══ -->
  <div *ngIf="showLogin" class="modal-overlay" (click)="showLogin = false">
    <div class="modal-content" (click)="$event.stopPropagation()">
      <button (click)="showLogin = false" class="close-btn">✕</button>
      <app-login (loginSuccess)="onLoginSuccess()"></app-login>
    </div>
  </div>
</div>
